[CmdletBinding(SupportsShouldProcess=$true)]
param([string]$ClusterName='.',[string]$ResourceName,[switch]$StartResource,[switch]$RestartResource,[string]$NodeName,[switch]$ResumeNode,[switch]$ClearNodeQuarantine,[switch]$RunValidation,[string]$OutputPath="$env:USERPROFILE\Desktop\ClusterRepair")
$ErrorActionPreference='Stop';Import-Module FailoverClusters -ErrorAction Stop;New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($StartResource-or$RestartResource-or$ResumeNode-or$ClearNodeQuarantine-or$RunValidation)){throw'Choose at least one repair action.'}
Get-ClusterNode -Cluster $ClusterName|Export-Clixml (Join-Path $OutputPath 'nodes-before.xml');Get-ClusterResource -Cluster $ClusterName|Export-Clixml (Join-Path $OutputPath 'resources-before.xml')
if($StartResource){if(-not$ResourceName){throw'-ResourceName is required.'};if($PSCmdlet.ShouldProcess($ResourceName,'Start cluster resource')){Start-ClusterResource -Cluster $ClusterName -Name $ResourceName;L'Resource started.'}}
if($RestartResource){if(-not$ResourceName){throw'-ResourceName is required.'};if($PSCmdlet.ShouldProcess($ResourceName,'Restart cluster resource')){Stop-ClusterResource -Cluster $ClusterName -Name $ResourceName;Start-ClusterResource -Cluster $ClusterName -Name $ResourceName;L'Resource restarted.'}}
if($ResumeNode){if(-not$NodeName){throw'-NodeName is required.'};if($PSCmdlet.ShouldProcess($NodeName,'Resume cluster node')){Resume-ClusterNode -Cluster $ClusterName -Name $NodeName -Failback NoFailback;L'Node resumed.'}}
if($ClearNodeQuarantine){if(-not$NodeName){throw'-NodeName is required.'};if($PSCmdlet.ShouldProcess($NodeName,'Clear cluster node quarantine')){Start-ClusterNode -Cluster $ClusterName -Name $NodeName -ClearQuarantine;L'Node quarantine cleared.'}}
if($RunValidation-and$PSCmdlet.ShouldProcess($ClusterName,'Run cluster validation tests')){Test-Cluster -Cluster $ClusterName -Include 'System Configuration','Network','Storage','Inventory' -ReportName (Join-Path $OutputPath 'ClusterValidation')|Out-Null;L'Cluster validation completed.'}
Get-ClusterNode -Cluster $ClusterName|Export-Clixml (Join-Path $OutputPath 'nodes-after.xml');Get-ClusterResource -Cluster $ClusterName|Export-Clixml (Join-Path $OutputPath 'resources-after.xml');L'Repair workflow finished.'